cd /tmp/sv-35fd6a05d0ab4efb83ac02b98ad8677f/advanced-multi-complexity && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: project_name -> framework -> package -> version
def build_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        m[name] = {}
        for fw in p['frameworks']:
            m[name][fw['framework']] = {pkg['id']: pkg['resolvedVersion'] for pkg in fw['topLevelPackages']}
    return m

b = build_map(baseline)
a = build_map(after)

print('=== CHANGES ===')
changes = False
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for fw in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        bp = b.get(proj,{}).get(fw,{})
        ap = a.get(proj,{}).get(fw,{})
        for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
            bv = bp.get(pkg)
            av = ap.get(pkg)
            if bv != av:
                changes = True
                print(f'  {proj} [{fw}] {pkg}: {bv} -> {av}')

if not changes:
    print('  (none)')

print()
print('=== UNCHANGED (sample) ===')
count = 0
for proj in sorted(b.keys()):
    for fw in sorted(b.get(proj,{}).keys()):
        for pkg, ver in sorted(b[proj][fw].items()):
            av = a.get(proj,{}).get(fw,{}).get(pkg)
            if ver == av:
                count += 1
if count:
    print(f'  {count} package-project-framework combinations unchanged')
"

